// Coerce a string from the admin form to the knob's runtime type.
export function coerce(kind, str) {
  if (kind === 'int') return Math.round(Number(str));
  if (kind === 'float' || kind === 'ms' || kind === 'ratio01' || kind === 'worldunits') return Number(str);
  if (kind === 'flag') return str === 'true' || str === '1';
  return str;
}
